Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <algorithm>

int main()
{
    std::string target_word; // the word to search for
    std::string filename; // the name of the input file
    std::vector<std::string> words; // to store the words from the file

    // prompt the user to enter the word to search for
    std::cout << "Enter the word to search for: ";
    std::getline(std::cin, target_word);

    // prompt the user to enter the filename
    std::cout << "Enter the filename: ";
    std::getline(std::cin, filename);

    // open the file for reading
    std::ifstream input_file(filename);
    std::string line;

    // if the file is not found, terminate the program
    if (!input_file.is_open())
    {
        std::cerr << "Error: Could not open file: " << filename << std::endl;
        return 1;
    }

    // read the contents of the file line by line
    while (std::getline(input_file, line))
    {
        // split the line into words and store them in the vector
        std::size_t prev = 0, pos = 0;
        std::string token;
        while ((pos = line.find(" ", pos))!= std::string::npos)
        {
            token = line.substr(prev, pos - prev);
            words.push_back(token);
            prev = pos + 1;
            pos = line.find(" ", prev);
            if (pos == std::string::npos)
            {
                token = line.substr(prev);
                words.push_back(token);
            }
        }

        // count the occurrences of the target word
        std::size_t count = std::count(words.begin(), words.end(), target_word);

        // reset the vector for the next iteration
        words.clear();

        // print the number of occurrences of the target word
        std::cout << "Number of occurrences of \"" << target_word << "\" in the file: " << count << std::endl;
    }

    // close the file
    input_file.close();

    return 0;
}
```

This program prompts the user to enter the target word and filename, reads the file line by line, splits each line into words, counts the occurrences of the target word, and prints the number of occurrences at the end of each line. The vector `words` is reset after each line to avoid counting the same word multiple times in the same line. After all lines have been processed, the program closes the file and returns 0 to indicate successful termination.

